double closestPairSubset(std::vector<Point> const& subsetPoints) {
	// Initialize minimum distance to infinity
	double minDistance = INFINITY;

	// Iterate over all pairs of points in the subset
	for (int i = 0; i < subsetPoints.size(); ++i) {
		for (int j = i + 1; j < subsetPoints.size(); ++j) {
			// Calculate distance between current pair of points
			double dist = distance(subsetPoints[i], subsetPoints[j]);

			// Update minimum distance if current distance is smaller
			if (dist < minDistance) {
				minDistance = dist;
			}
		}
	}

	return minDistance;
}

// Function to find the closest pair of points in a vector using MPI
double closestPair(std::vector<Point> const& points) {
	int numRanks, rank;
	MPI_Comm_size(MPI_COMM_WORLD, &numRanks);
	MPI_Comm_rank(MPI_COMM_WORLD, &rank);

	// Calculate number of points per process
	int numPointsPerProcess = (int)(points.size() / numRanks);
	if (rank == numRanks - 1) {
		numPointsPerProcess += points.size() % numRanks;
	}

	// Create a subset of points for this process
	std::vector<Point> subsetPoints(points.begin() + rank * numPointsPerProcess,
									points.begin() + std::min((long long)(rank + 1) * numPointsPerProcess, (long long)points.size()));

	// Calculate minimum distance in this process
	double minDistance = closestPairSubset(subsetPoints);

	// If this is the root process, collect distances from all processes and find global minimum
	if (rank == 0) {
		std::vector<double> distances(numRanks);
		for (int i = 1; i < numRanks; ++i) {
			MPI_Recv(&distances[i], 1, MPI_DOUBLE, i, 0, MPI_COMM_WORLD, MPI_STATUS_IGNORE);
		}

		double minGlobalDistance = INFINITY;
		for (double dist : distances) {
			if (dist < minGlobalDistance) {
				minGlobalDistance = dist;
			}
		}

		return minGlobalDistance;
	} else {
		// Otherwise, send minimum distance to the root process
		MPI_Send(&minDistance, 1, MPI_DOUBLE, 0, 0, MPI_COMM_WORLD);
	}

	return INFINITY; // This should never be reached
}

int main(int argc, char** argv) {
	MPI_Init(&argc, &argv);

	int numRanks, rank;
	MPI_Comm_size(MPI_COMM_WORLD, &numRanks);
	MPI_Comm_rank(MPI_COMM_WORLD, &rank);

	if (rank == 0) {
		std::vector<Point> points = {{2, 3}, {12, 30}, {40, 50}, {5, 1}, {12, 10}, {3, 4}};
